import {
  useEffect,
  useState
} from "react";

import {
  getFacultySubmissions
} from "../../api/hodApi";

function HodDashboard() {

  const [
    submissions,
    setSubmissions
  ] = useState([]);

  const [
    loading,
    setLoading
  ] = useState(true);

  useEffect(() => {

    fetchData();

  }, []);

  const fetchData =
    async () => {

      try {

        const response =
          await getFacultySubmissions();

        setSubmissions(
          response.data.submissions || []
        );

      } catch (error) {

        console.error(error);

      } finally {

        setLoading(false);

      }

    };

  const pendingCount =
    submissions.filter(
      (s) =>
        s.status ===
        "Pending HOD Approval"
    ).length;

  const approvedCount =
    submissions.filter(
      (s) =>
        s.status ===
        "Approved by HOD"
    ).length;

  const rejectedCount =
    submissions.filter(
      (s) =>
        s.status ===
        "Rejected by HOD"
    ).length;

  return (

    <div
      style={{
        padding: "30px"
      }}
    >

      <h1>
        HOD Dashboard
      </h1>

      <p>
        Welcome HOD
      </p>

      <div
        style={{
          display: "grid",
          gridTemplateColumns:
            "repeat(auto-fit,minmax(250px,1fr))",
          gap: "20px",
          marginTop: "25px"
        }}
      >

        <div
          className="card"
        >
          <h2>
            {pendingCount}
          </h2>

          <p>
            Pending Reviews
          </p>
        </div>

        <div
          className="card"
        >
          <h2>
            {approvedCount}
          </h2>

          <p>
            Approved
          </p>
        </div>

        <div
          className="card"
        >
          <h2>
            {rejectedCount}
          </h2>

          <p>
            Rejected
          </p>
        </div>

      </div>

      <h2
        style={{
          marginTop: "40px"
        }}
      >
        Recent Faculty Submissions
      </h2>

      {

        loading ?

        <p>
          Loading...
        </p>

        :

        <table
          style={{
            width: "100%",
            marginTop: "20px",
            borderCollapse:
              "collapse"
          }}
        >

          <thead>

            <tr>

              <th style={thStyle}>
                Faculty
              </th>

              <th style={thStyle}>
                Email
              </th>

              <th style={thStyle}>
                Department
              </th>

              <th style={thStyle}>
                Quarter
              </th>

              <th style={thStyle}>
                Status
              </th>

            </tr>

          </thead>

          <tbody>

            {

              submissions.map(
                (
                  item
                ) => (

                  <tr
                    key={
                      item._id
                    }
                  >

                    <td style={tdStyle}>
                      {
                        item.facultyName
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.facultyEmail
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.department
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.quarter
                      }
                    </td>

                    <td style={tdStyle}>
                      {
                        item.status
                      }
                    </td>

                  </tr>

                )
              )

            }

          </tbody>

        </table>

      }

    </div>

  );

}

const thStyle = {

  padding: "12px",

  background:
    "#2563eb",

  color:
    "white",

  textAlign:
    "left"

};

const tdStyle = {

  padding: "12px",

  borderBottom:
    "1px solid #e5e7eb"

};

export default HodDashboard;
